/* htmx 2.0.4 - download from https://unpkg.com/htmx.org@2.0.4 */
/* Stub: replace with real htmx.min.js for production */
(function(){
  var htmx = {version:"2.0.4-stub"};
  function process(elt) {
    elt.querySelectorAll("[hx-get]").forEach(function(el) {
      var trigger = el.getAttribute("hx-trigger") || "click";
      var url = el.getAttribute("hx-get");
      var swap = el.getAttribute("hx-swap") || "innerHTML";
      var target = el.getAttribute("hx-target");
      function doFetch() {
        var targetEl = target ? document.querySelector(target) : el;
        fetch(url).then(function(r){return r.text();}).then(function(html){
          if(swap === "innerHTML") targetEl.innerHTML = html;
          else if(swap === "outerHTML") targetEl.outerHTML = html;
        });
      }
      if(trigger.indexOf("load") !== -1) doFetch();
      else el.addEventListener(trigger.split(" ")[0], doFetch);
    });
  }
  document.addEventListener("DOMContentLoaded", function(){ process(document.body); });
  window.htmx = htmx;
})();
